UPDATE envio
SET idCliente = #{idCliente}, destiNomb = #{destiNomb}, destiApellidoPaterno = #{destiApellidoPaterno},
    destiApellidoMaterno = #{destiApellidoMaterno}, idSucursalOrigen = #{idSucursalOrigen},
    calle = #{calle}, numero = #{numero}, colonia = #{colonia}, codigoPostal = #{codigoPostal},
    ciudad = #{ciudad}, estado = #{estado}, idConductor = #{idConductor}
WHERE idEnvio = #{idEnvio}

UPDATE envio
SET idEstatus = #{idEstatus}
WHERE idEnvio = #{idEnvio}

UPDATE envio
SET costoTotal = #{costoTotal}
WHERE idEnvio = #{idEnvio}

UPDATE envio
SET idConductor = #{idConductor}
WHERE idEnvio = #{idEnvio}

UPDATE envio
SET motivoEstatus = #{motivoEstatus}
WHERE idEnvio = #{idEnvio}
